query:
{
  managedIdentities(
    where: {
      OR: [
        {
          vms_SOME: {
            networkInterfaces_SOME: {
              publicIp_NOT: null
              securityGroups_SOME: {
                rules_SOME: {
                  direction: "Inbound"
                  action: "Allow"
                  OR: [
                    { sources_INCLUDES: "cidr:0.0.0.0/0" }
                    { sources_INCLUDES: "cidr:::/0" }
                    { sources_INCLUDES: "tag:Internet" }
                    { sources: [] }
                  ]
                }
              }
            }
          }
        }
        {
          functions_SOME: {
            bindings_SOME: {
              direction: "in"
              type: "httpTrigger"
              authLevel: "anonymous"
            }
          }
        }
        {
          appServices_SOME: {
            OR: [
              { authSettings: null }
              { authSettings: { NOT: { enabled: true } } }
            ]
          }
        }
      ]
    }
  ) {
    ...AssetFragment
  }
}
